import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"191. Overpayment Of Wages Royal Children S Hospital","description":"","frontmatter":{"title":"191. Overpayment Of Wages Royal Children S Hospital","eba":"Mental Health Services 2024-2028","topics":["wages"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/wages/191-overpayment-of-wages-royal-children-s-hospital.md","filePath":"ebas/mental-health/management-admin/wages/191-overpayment-of-wages-royal-children-s-hospital.md"}'),r={name:"ebas/mental-health/management-admin/wages/191-overpayment-of-wages-royal-children-s-hospital.md"};function s(l,e,i,h,p,m){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_191-overpayment-of-wages-royal-children-s-hospital" tabindex="-1">191. Overpayment Of Wages Royal Children S Hospital <a class="header-anchor" href="#_191-overpayment-of-wages-royal-children-s-hospital" aria-label="Permalink to &quot;191. Overpayment Of Wages Royal Children S Hospital&quot;">​</a></h1><p>This clause only applies to Management and Administrative Officers at Royal Children’s Hospital classified under Part 2 of of this Agreement.</p><p><strong>191.1</strong> In the case of an overpayment of wages, the Employer shall notify the Employee in writing of details of the error. The Employer will correct the overpayment by fortnightly deduction from the Employee’s pay, in a minimum instalment of 10% of the Employee’s fortnightly salary or the total amount, until the full amount of the overpayment has been reimbursed.</p><p><strong>191.2</strong> The above clause 191.1 does not apply in the case of errors of law.</p><p><strong>191.3</strong> Where a single overpayment exceeds the Employee’s normal four-week salary, the Employer reserves the right to seek to have the overpayment repaid in more than 10% instalments.</p><p><strong>191.4</strong> If the Employee satisfies the Employer that they are unable to meet the repayment schedule, the Employee may apply to vary the payment schedule. Agreement to such applications shall not be unreasonably withheld.</p>',6)])])}const f=a(r,[["render",s]]);export{d as __pageData,f as default};
